# JavaScript Math Operations Function

```javascript
// Function to perform basic math operations
function calculate(operation, a, b) {
    switch(operation) {
        case 'add':
            return a + b;
        case 'subtract':
            return a - b;
        case 'multiply':
            return a * b;
        case 'divide':
            if (b !== 0) return a / b;
            else return 'Error: Division by zero';
        default:
            return 'Invalid operation';
    }
}

// Example usage
console.log(calculate('add', 5, 3));  // Output: 8
console.log(calculate('divide', 10, 2)); // Output: 5
```
